// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ProjectUpdateThread) predicate.ProjectUpdateThread {
	return predicate.ProjectUpdateThread(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ProjectUpdateThread) predicate.ProjectUpdateThread {
	return predicate.ProjectUpdateThread(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ProjectUpdateThread) predicate.ProjectUpdateThread {
	return predicate.ProjectUpdateThread(sql.NotPredicates(p))
}
